<?php
namespace App\Console\Commands;use App\Models\Document;use App\Models\DocumentAuditLog;use Illuminate\Console\Command;
class MarkExpiredDocuments extends Command{protected $signature='documents:check-expiry'; protected $description='Mark verified documents as expired when expiry date has passed'; public function handle(){ $count=0; Document::whereDate('expiry_date','<',now()->toDateString())->where('status','verified')->chunkById(200,function($docs) use (&$count){foreach($docs as $d){$old=$d->status;$d->update(['status'=>'expired']);DocumentAuditLog::create(['document_id'=>$d->id,'business_id'=>$d->business_id,'action'=>'document_expired','old_values'=>['status'=>$old],'new_values'=>['status'=>'expired'],'performed_at'=>now()]);$count++;}}); $this->info("updated=$count"); return self::SUCCESS; }}